// Unwrap directly from the HTTP Request output
const rawResults = $input.first().json.results;

const events = [
  "AI Workshop",
  "Career Development Seminar",
  "Startup Innovation Summit"
];

// Step 1: Transform all participants
const participants = rawResults.map((user, index) => {
  return {
    id: index + 1,
    name: `${user.name.first} ${user.name.last}`,
    email: user.email,
    gender: user.gender,
    country: user.location.country,
    age: user.dob.age,
    event: events[index % 3],
    registeredAt: new Date().toISOString(),
    status: "registered",
    isDuplicate: false
  };
});

// Step 2: Pick 15 random participants and duplicate them
const shuffled = [...participants].sort(() => Math.random() - 0.5);
const toRepeat = shuffled.slice(0, 15);

const duplicates = toRepeat.map(p => ({
  ...p,
  registeredAt: new Date().toISOString(),
  _isDuplicateInjected: true
}));

// Step 3: Combine originals + duplicates
const combined = [...participants, ...duplicates];

return combined.map(item => ({ json: item }));

const registrations = $input.first().json.registrations;

const seen = new Map();
const processed = [];

for (const reg of registrations) {
  const key = `${reg.email}|${reg.event}`;

  if (seen.has(key)) {
    processed.push({ ...reg, isDuplicate: true, status: "duplicate" });
  } else {
    seen.set(key, true);
    processed.push({ ...reg, isDuplicate: false, status: "registered" });
  }
}

const valid = processed.filter(r => !r.isDuplicate);
const duplicates = processed.filter(r => r.isDuplicate);

return [{
  json: {
    allRegistrations: processed,
    validRegistrations: valid,
    duplicateRegistrations: duplicates,
    totalCount: processed.length,
    validCount: valid.length,
    duplicateCount: duplicates.length
  }
}];

const { validRegistrations, duplicateRegistrations,
        totalCount, validCount, duplicateCount } = $input.first().json;

// 70% chance of attending — realistic no-show rate for professional events
const withAttendance = validRegistrations.map(reg => ({
  ...reg,
  attendance: Math.random() < 0.70 ? "Attended" : "Absent"
}));

return [{
  json: {
    attendanceRecords: withAttendance,
    duplicateRegistrations,
    totalCount,
    validCount,
    duplicateCount
  }
}];

const { attendanceRecords, duplicateRegistrations,
        totalCount, validCount, duplicateCount } = $input.first().json;

const events = [
  "AI Workshop",
  "Career Development Seminar",
  "Startup Innovation Summit"
];

// Per-event breakdown
const eventStats = {};
for (const ev of events) {
  const group = attendanceRecords.filter(r => r.event === ev);
  const attended = group.filter(r => r.attendance === "Attended");
  const absent = group.filter(r => r.attendance === "Absent");

  eventStats[ev] = {
    totalRegistered: group.length,
    attended: attended.length,
    absent: absent.length,
    attendanceRate: group.length > 0
      ? ((attended.length / group.length) * 100).toFixed(1) + "%"
      : "0%",
    noShowRate: group.length > 0
      ? ((absent.length / group.length) * 100).toFixed(1) + "%"
      : "0%"
  };
}

// Leaderboard — ranked by attendance rate (Bonus 1)
const leaderboard = Object.entries(eventStats)
  .sort((a, b) => parseFloat(b[1].attendanceRate) - parseFloat(a[1].attendanceRate))
  .map(([name, stats], i) => ({ rank: i + 1, event: name, ...stats }));

const totalAttended = attendanceRecords.filter(r => r.attendance === "Attended").length;
const totalAbsent = attendanceRecords.filter(r => r.attendance === "Absent").length;

return [{
  json: {
    attendanceRecords,
    duplicateRegistrations,
    eventStats,
    leaderboard,
    summary: {
      totalRegistrations: totalCount,
      validRegistrations: validCount,
      duplicateRegistrations: duplicateCount,
      totalAttended,
      totalAbsent,
      overallAttendanceRate: ((totalAttended / validCount) * 100).toFixed(1) + "%",
      overallNoShowRate: ((totalAbsent / validCount) * 100).toFixed(1) + "%",
      mostPopularEvent: leaderboard[0].event,
      leastPopularEvent: leaderboard[leaderboard.length - 1].event
    }
  }
}];

const { summary, eventStats, leaderboard } = $input.first().json;

const report = {
  reportTitle: "Event Registration & Attendance Analytics Report",
  generatedAt: new Date().toISOString(),

  registrationStatistics: {
    totalRegistrations: summary.totalRegistrations,
    validRegistrations: summary.validRegistrations,
    duplicateRegistrations: summary.duplicateRegistrations
  },

  eventStatistics: {
    mostPopularEvent: summary.mostPopularEvent,
    leastPopularEvent: summary.leastPopularEvent,
    breakdown: eventStats
  },

  attendanceStatistics: {
    totalAttended: summary.totalAttended,
    totalAbsent: summary.totalAbsent,
    attendanceRate: summary.overallAttendanceRate,
    noShowRate: summary.overallNoShowRate
  },

  leaderboard: leaderboard
};

return [{ json: report }];
